  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"jeju-winter-southwest-tangerine-snow-camellia-tour","locale":"en","product_id":"jeju-winter-southwest-tangerine-snow-camellia-tour","seo":{"pageTitle":"Jeju Winter Tour: Tangerine, Snow & Camellia | AtoC Korea","metaDescription":"Winter-only 9-hour Jeju small-group tour: Hallasan snow viewpoint, Camellia Hill peak bloom, hands-on tangerine picking, Jusangjeolli, Cheonjeyeon Falls. Dec–Feb.","primaryKeywords":["Jeju winter tour","Jeju tangerine picking","Camellia Hill Jeju","Jeju Hallasan snow","Jeju December tour"],"ogImage":"https://images.unsplash.com/photo-1577741314755-048d8525d31e?w=1200","title":"Jeju Winter Southwest Tour: Tangerine Picking, Snow & Camellia Hill | AtoC Korea"},"catalog_card":{"thumbnail":"https://images.unsplash.com/photo-1577741314755-048d8525d31e?w=800","title":"Jeju Winter Southwest Tour: Tangerine Picking, Snow & Camellia","priceLabel":"Price varies — confirm at booking","shortCardDescription":"A seasonal winter day-tour of southwest Jeju (December through February) built around the three things only Jeju does well in winter: snow on Hallasan''s slopes, red camellias in full bloom at Camellia Hill, and pick-your-own Jeju tangerines (gyul) at a working orchard. The route also covers Cheonjeyeon Falls, Jusangjeolli columnar cliffs, and the Osulloc Tea Museum. Hotel pickup in Jeju City, English/Chinese-speaking licensed guide.","tags":["small_group","jeju","winter","seasonal","tangerine","camellia","snow"],"rating":0,"reviewCount":0,"slug":"jeju-winter-southwest-tangerine-snow-camellia-tour","subtitle":"Snow on Hallasan, peak-bloom Camellia Hill, hands-on tangerine picking, plus Jusangjeolli and Cheonjeyeon — Jeju''s winter southwest in 9 hours.","region":"Southwest Jeju","duration":"9 hours","stopsCount":8,"badges":["Small Group","Jeju","Winter","Seasonal","Tangerine","Camellia","Snow"],"heroImage":"https://images.unsplash.com/photo-1577741314755-048d8525d31e?w=800"},"headlineLine1":"Snow on Hallasan, red camellia in full bloom,","headlineLine2":"and tangerines you pick yourself — winter Jeju in 9 hours","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t1119639","priceNote":"Small-group price not yet confirmed from listing snippet. Sister tour (Pink Muhly autumn version) is approximately $111 per person. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10},"hero":{"imageUrl":"https://images.unsplash.com/photo-1577741314755-048d8525d31e?w=1600","imagePosition":"center 35%","tagline":"The three things only Jeju does well in winter — snow, camellia, and citrus","pills":["small_group","jeju"],"meta":{"duration":"9 hours","region":"Southwest Jeju (winter route)","stops":"8 stops","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"clock","label":"Duration","value":"9 hours (typical 08:30–17:30)"},{"icon":"users","label":"Group","value":"Small group, English/Chinese-speaking guide"},{"icon":"calendar","label":"Best season","value":"December to February (camellia peak Dec–Jan, tangerine harvest Dec–Feb)"},{"icon":"hotel","label":"Pickup","value":"Free hotel pickup in Jeju City; +₩70,000 outside Jeju City"},{"icon":"footprints","label":"Walking","value":"Light to moderate — Hallasan stop is a viewpoint, not a hike"},{"icon":"ticket","label":"Includes","value":"Vehicle, licensed guide-driver, fuel/tolls/parking. Excludes: admissions, lunch, tangerine-picking fee"}],"galleryItems":[{"id":"g1","type":"photo","src":"https://images.unsplash.com/photo-1577741314755-048d8525d31e?w=1200","alt":"Snow-dusted ridgelines of Hallasan visible from a southwest viewpoint, with low forest in the foreground","caption":"Hallasan winter scenery from the southwest viewpoint","location":"Hallasan 1100 Road or Eorimok trailhead, central Jeju","atmosphere":"Crisp winter mountain air; snow-capped ridges visible even when coastal Jeju has none"},{"id":"g2","type":"photo","src":"https://images.unsplash.com/photo-1599946347371-68eb71b16afc?w=1200","alt":"Garden path lined with mature camellia trees in full red bloom","caption":"Camellia Hill in peak winter bloom (December-February)","location":"Camellia Hill, Andeok, southern Jeju","atmosphere":"Winter peak bloom across 6,000+ camellia trees and 500 varieties"},{"id":"g3","type":"photo","src":"https://images.unsplash.com/photo-1535139262971-c51845709a48?w=1200","alt":"Hands picking ripe orange tangerines from a low tree in a Jeju orchard","caption":"Jeju gyul (tangerine) orchard winter harvest","location":"A Jeju southwest tangerine orchard (specific farm rotates)","atmosphere":"Hands-on Jeju agricultural experience; clippers and baskets provided"},{"id":"g4","type":"photo","src":"https://images.unsplash.com/photo-1502175353174-a7a44e84da10?w=1200","alt":"Hexagonal columnar lava cliffs rising from a winter sea","caption":"Daepo Jusangjeolli columnar lava cliffs","location":"Daepo, Jungmun coast, southern Jeju","atmosphere":"UNESCO Geopark winter coastline; dramatic surf at the cliff base"},{"id":"g5","type":"photo","src":"https://images.unsplash.com/photo-1601471569526-2c7d5e1b7e5f?w=1200","alt":"Three-tier waterfall in a forested valley with the Seonimgyo Bridge crossing above","caption":"Cheonjeyeon Waterfall and the Seonimgyo Bridge of Seven Nymphs","location":"Cheonjeyeon Falls, Seogwipo, southern Jeju","atmosphere":"Forest valley waterfall stop; the bridge depicts seven heavenly nymphs in legend"}],"itineraryStops":[{"number":1,"time":"08:30","duration":"20 min","name":"Hotel Pickup (Jeju City / Jungmun area)","category":"Pickup","description":"**Hotel pickup window 08:30–09:00** from designated Jeju City or Jungmun-area hotels. Driver and English-speaking guide arrive in a **minicoach (8–15 pax shared)** with name placard at the hotel lobby; the operator''s 24/7 contact number is provided at booking. Pickup catchment includes downtown Jeju City hotels (Maison Glad, Lotte City, Ramada Plaza, etc.), Jeju Airport-area accommodations, and the Jungmun Tourist Complex (Lotte Hotel Jeju, Shilla Jeju, Hyatt). Guests outside the standard pickup zone can join at one of the operator''s three meeting points (Jeju Bus Terminal, Halla Department Store, Yeon-dong Crossroads). **Winter dispatch consideration**: morning departure is delayed by ~15 min when overnight snowfall on Route 1100 (the Hallasan ascent road) is reported — the guide confirms road status with the operator''s morning weather brief and adjusts pickup accordingly. Guests are advised to dress in **winter layers + waterproof outer shell** + non-slip footwear (the day''s exposure includes Hallasan snow trail, open-air Camellia Hill garden, outdoor tangerine orchard, and Jusangjeolli''s wind-exposed cliff edge). Crampons can be rented at the Hallasan trailhead (~₩8,000) but the operator carries 2–3 spare sets in the vehicle. All beverages, snacks, and lunch are out-of-pocket; the vehicle has a small cooler with hot tea/coffee available throughout the day.","highlights":["**Pickup window 08:30–09:00** from Jeju City + Jungmun hotels","Minicoach (8–15 pax shared); English-speaking guide + driver","Three off-hotel meeting points: Bus Terminal, Halla Dept Store, Yeon-dong Crossroads","**Winter departure can shift +15 min** if overnight snowfall on Route 1100 reported","Crampons rentable at Hallasan trailhead (~₩8,000); operator carries spare sets","Hot tea/coffee available in vehicle throughout the day"],"whyOnRoute":"**Pickup is timed to clear Hallasan summit access window** — Eorimok last-entry is **~11:30 in winter** (vs ~12:30 in other seasons), so the day must start by 09:00 to give the group full hike time before the entry cutoff. Layered hotel pickup (downtown + Jungmun + 3 meeting points) absorbs guests across Jeju''s two main accommodation clusters in a single sweep, keeping the minicoach at the 8–15 pax target without dispatching a separate van.","_poi_meta":{"poi_key":"OPS_pickup_winter_southwest","kb_version":"1.22","verified_date":"2026-04-29","sources":["AtoC Korea operations notes (Jeju winter dispatch protocol)","Hallasan National Park (Eorimok winter last-entry ~11:30)","Jeju Provincial Tourism (hotel cluster catchment)"]}},{"number":2,"time":"09:30","duration":"120 min","name":"Hallasan Eorimok Trail (Winter Snow Hike)","category":"National Park & Winter Hike","description":"**Eorimok Trail** (어리목 탐방로) is one of **two easiest of Hallasan National Park''s 5 trails** (the others requiring advance reservation include Seongpanak and Gwaneumsa for summit access — Eorimok and Yeongsil are the **non-summit, no-reservation routes** that are always available). The trail leads **4.7 km one-way to Witseoreum Shelter (1,700 m elevation)**, the official turnaround at the Witseoreum plateau — **NOT the summit** (1,950 m Baengnokdam crater is reservation-only via Seongpanak/Gwaneumsa). For a **9-hour day-tour**, the standard winter-season practice is to hike **1.5–2 km in** (~45 min one-way) to reach the **forest-to-plateau transition** where dwarf bamboo fields open up to dramatic Hallasan-summit-wall views, then return to the trailhead — covering ~3–4 km total in ~90 min hiking time + ~30 min trail buffer. **Winter conditions** (November–March): the trail''s most dramatic season — **snow-encrusted dwarf trees create a ''frozen guardian'' landscape** widely photographed by Korean hiking clubs who plan last-minute trips after fresh snowfalls; **hoarfrost** + occasional **sea-of-clouds below the ridge** + mountain-side snow drifts make this Jeju''s signature winter photo. **Crampons recommended November–March** (basic strap-on sets sold at the trailhead ~₩8,000 / ~$8 USD; the operator also carries 2–3 spare sets in-vehicle). **FREE admission** (Hallasan National Park has no entry fee); **opens 05:00, last entry ~11:30 in winter** (vs ~12:30 other seasons — the early winter cutoff is the day''s hard schedule constraint). **25 min drive from Jeju City** via Route 1100; free trailhead car park (fills on weekends — the operator schedules early arrival in peak season). Bus access also available via **Bus 240** from Jeju Bus Terminal.","highlights":["**Eorimok = 1 of 2 easiest Hallasan trails** + **no reservation required** (unlike summit-access Seongpanak/Gwaneumsa)","**4.7 km to Witseoreum Shelter (1,700 m)** — non-summit; tour groups typically go 1.5–2 km in","**FREE admission** — Hallasan National Park has no entry fee","**Last entry ~11:30 in winter** (vs ~12:30 other seasons) — hard day-schedule constraint","**''Frozen guardians''** — snow-encrusted dwarf trees in winter; signature Jeju winter photo","**Hoarfrost + sea-of-clouds + summit-wall views** on clear winter days","**Crampons required Nov–Mar** — sold at trailhead ~₩8,000; operator carries spares","**25 min drive from Jeju City** via Route 1100 (Korea''s highest national highway)","Bus 240 access from Jeju Bus Terminal; Bus 1100/1100-1 weekend service"],"whyOnRoute":"**Hallasan Eorimok is the day''s altitude + winter-snow anchor** — Jeju''s defining winter landscape happens above 800 m, and Eorimok delivers it at moderate hiking effort (1.5–2 km tour-group walk) without the summit-route reservation constraint that excludes most international cruise/day-trip itineraries. The trail''s **forest-to-plateau transition** at ~1.5 km in is precisely where Jeju''s most-photographed winter scene unfolds — **snow-encrusted dwarf bamboo + ''frozen guardian'' trees + Hallasan summit wall up-close** — and it''s the only stop in the catalog that captures this. Pacing the Hallasan stop **first in the day** also serves the operational schedule: the **~11:30 winter last-entry cutoff** at Eorimok is non-negotiable, so any other stop sequence would force a sub-90-min hike window or risk missing the cutoff entirely on a delayed pickup day. FREE admission also keeps the day''s per-pax cost basis competitive against other winter Jeju tours.","_poi_meta":{"poi_key":"hallasan_eorimok_trail","kb_version":"1.22","verified_date":"2026-04-29","sources":["Hallasan National Park / english.jeju.go.kr (trail length, elevation, hours)","AllTrails (Eorimok trail mileage variants 8.7 mi / 7 mi point-to-point with Yeongsil)","Hunting for Bliss / Fork and Foot (winter trail conditions, ''frozen guardian'' landscape, hike timing)","VisitKorea / english.visitkorea.or.kr (FREE admission, no-reservation status)","Jeju Bus Information System (Bus 240 + Routes 1100/1100-1)"]}},{"number":3,"time":"12:00","duration":"60 min","name":"Tangerine (Gyul) Picking Experience — Winter Hallabong Peak","category":"Agritourism Experience","description":"**Jeju tangerine (gyul / 감귤) picking experience** at a guide-vetted farm in the **Seogwipo / Namwon-eup / Jungmun area**, selected for the day''s specific date based on **variety calendar** — December–January is **Hallabong (한라봉) peak** (mid-Dec to mid-Jan window), Jeju''s most famous easy-peel hybrid. **Jeju citrus has been gifted seasonally to Korean royalty since the Baekje period (4th–7th century) through Silla and Goryeo dynasties** — **a cultivation tradition over 1,500 years old** that is still anchored to Jeju''s volcanic soil + warm-temperate climate. **Standard format**: the farm provides a basket and scissors (some include gloves); **eat-as-you-pick is unlimited on-farm** (tasting all you want), and guests purchase take-home weight by the kg or as part of the entry fee. **Typical pricing**: **₩5,000–15,000 per person entry** (often includes 1 kg take-home), **+₩2,500–₩15,000 per additional kg** depending on variety. **Citrus calendar by season**: Spring (Mar–May) Hallabong / Jinjihyang / Seminole; Summer (Jun–Aug) greenhouse tangerines + blueberries; Fall (Sep–Nov) early-harvest Noji; **Winter Peak (Dec–Jan) Noji + Hallabong**; Late Winter (Feb) Hallabong + Cheonhyehyang. **Featured varieties**: Hallabong (most famous, juicy/sweet/easy-peel; Dec–Jan peak), Cheonhyehyang (large hybrid tangerine + orange), Hwanggeumhyang (Hallabong + Cheonhyehyang cross), Red Hyang (red-orange flesh, Hallabong + Noji blend), Hagyul (sour, citrus-ade base), Dangyuja (tangy heritage cultivar). **Vetted farms in the rotation**: **Gyulhyangi Experience Farm** (₩7,000 entry incl 1 kg, English-friendly staff, complimentary tangerine tea + biscuit + jam tasting); **Bong Bong Tangerine Farm** (Namwon-eup, ₩5,000 entry + ₩2,500/kg, on-site cafe, named after owner''s golden retriever); **Choenamdan Experience Farm** (monorail ride to orchards, Hallabong + Cheonhyehyang); **Jeju Southernmost Theme Park** (GAP-certified, year-round greenhouse picking, monorail, petting zoo with rabbits/deer/ducks/black pigs); **Jejue In Farm** (cafe + orchard combo, Hallabong-ade signature drink). **Rain backup**: most farms have greenhouse sections — winter rain or unexpected weather rarely cancels the stop. **Family-friendly**: easy flat orchard paths, suitable for all ages and stroller-accessible at most farms; children under 3 cannot ride monorail at Choenamdan / Southernmost.","highlights":["**Jeju citrus tradition over 1,500 years old** — royal gift since Baekje period (4th–7th c)","**Hallabong peak mid-Dec to mid-Jan** — most famous variety, easy-peel + juicy + sweet","**Eat-as-you-pick unlimited on-farm**; take-home weighed at ₩2,500–15,000/kg","**Entry ₩5,000–15,000/pax** (often includes 1 kg take-home)","**7 featured varieties**: Hallabong / Cheonhyehyang / Hwanggeumhyang / Red Hyang / Gamgyul / Hagyul / Dangyuja","**Gyulhyangi Farm** — English-friendly staff + complimentary tangerine tea/jam tasting","**Jeju Southernmost Theme Park** — GAP-certified, year-round greenhouse, monorail + petting zoo","**Family-friendly** — flat orchard paths, stroller-accessible, kid-favorite","**Rain backup** — most farms have greenhouse picking sections"],"whyOnRoute":"**Tangerine picking is the day''s signature winter agritourism anchor** — and the schedule is built around the **Hallabong peak window (mid-Dec to mid-Jan)** that gives this tour its name. Positioning it **third in the day** (12:00 after Hallasan, before lunch) takes advantage of guests'' post-hike appetite — eat-as-you-pick is generous, and many guests take 5–10 tangerines on-farm before lunch arrives. The Seogwipo / Namwon-eup farm cluster is also **15–25 min from Hallasan trailhead and 10 min from Camellia Hill** (the next stop), keeping the day''s geographic flow tight. **Variety choice is date-driven**: the operator selects Hallabong-peaking farms in late Dec–early Jan, Hallabong-fading + Cheonhyehyang-rising farms in late Jan–Feb, and year-round greenhouse-equipped farms (Jeju Southernmost) for off-window dates — **giving the tour a stable picking experience across the entire Dec–Feb winter window**, not just peak weeks. Take-home tangerines also serve as a tangible, edible souvenir — competitively priced vs city-market or Olle Maeil Market boxes.","_poi_meta":{"poi_key":"jeju_tangerine_picking_experience","kb_version":"1.22","verified_date":"2026-04-29","sources":["VisitKorea / english.visitkorea.or.kr (Jeju citrus history; royal-gift tradition since Baekje)","Visit Jeju (variety calendar; cultivation tradition)","Jeju Provincial Government (Hallabong + Cheonhyehyang + Hwanggeumhyang + Red Hyang varieties)","Klook / Trazy / Mindtrip (farm rotation: Gyulhyangi, Bong Bong, Choenamdan, Jeju Southernmost, Jejue In; pricing ₩5,000–15,000)","Korea Agricultural GAP Certification (Jeju Southernmost Theme Park year-round greenhouse)"]}},{"number":4,"time":"13:15","duration":"60 min","name":"Lunch (Southern Jeju local restaurant)","category":"Lunch","description":"**Lunch at a guide-vetted southern Jeju restaurant** — typically in the Seogwipo or Andeok-myeon area, fitting the day''s geographic flow (between tangerine farm and Camellia Hill). **Two typical options** depending on group preference and seasonal availability: **(1) Black Pork BBQ** (제주 흑돼지) — Jeju''s signature ingredient; the indigenous **Jeju Black Pig was designated Natural Monument of Korea in 2015**, and pork-belly cuts are grilled over charcoal at the table with traditional banchan (winter banchan often includes Jeju winter cabbage kimchi + radish + Mom-guk seaweed soup); or **(2) Galchi-jorim** (갈치조림 — braised hairtail with radish, soy-chili sauce) — winter is the **Jeju hairtail peak season** (Nov–Feb), with the season''s deepest fish from the southern coast reaching tables within hours of dockside landing. **Vegetarian options** available at most venues with advance notice (Bibimbap with Jeju seasonal vegetables + Mom-guk; the guide confirms ~30 min ahead). **Winter signature beverages**: hot **yujacha** (citron tea — same Jeju citrus family as Hallabong), **omegisul** (Seongeup family-recipe rice-millet liquor — winter warming spirit), and the local **Hallasan Soju** (~₩5,000). All venues in the rotation accept **major cards (Visa/Mastercard) + cash KRW**; bilingual photo menus (English/Chinese) are standard. **Lunch is NOT included** in standard pricing — typical out-of-pocket **₩15,000–25,000/pax**; inclusive lunch upgrade available on booking. **Winter rain backup**: all rotation venues have indoor seating, so a southern-Jeju winter shower never disrupts the meal.","highlights":["Guide-vetted Seogwipo / Andeok-myeon-area restaurant","**Black Pork BBQ** (Natural Monument 2015) or **winter Galchi-jorim** (Nov–Feb hairtail peak)","Vegetarian options (Bibimbap + Mom-guk) on advance notice","**Yujacha** (citron tea) + **Omegisul** (winter warming spirit) signature beverages","Card + cash accepted; bilingual photo menus","**Lunch NOT included** — ₩15,000–25,000/pax out-of-pocket","All venues have indoor seating — winter rain backup"],"whyOnRoute":"**Lunch positioning at 13:15 absorbs any morning Hallasan + tangerine schedule slip** — by this point in winter, the Eorimok trail and orchard schedules are behind the group, and lunch acts as flex buffer before the afternoon''s three substantive stops. Geographic positioning between tangerine farm (Namwon-eup area) and Camellia Hill (Andeok-myeon) means **zero detour cost** — the lunch venue rotation is on the natural drive line.","_poi_meta":{"poi_key":"OPS_lunch_winter_south","kb_version":"1.22","verified_date":"2026-04-29","sources":["Jeju Black Pig Natural Monument designation (2015, Cultural Heritage Administration)","Visit Jeju (winter seafood — galchi-jorim Nov–Feb peak)","AtoC Korea operations notes (winter southern Jeju lunch venue rotation)"]}},{"number":5,"time":"14:30","duration":"75 min","name":"Camellia Hill (year-round signature flower garden)","category":"Botanical Garden — Largest Camellia Arboretum in the East","description":"**Camellia Hill (카멜리아힐, Jeju Camellia Arboretum)** is a **172,000 m² botanical garden** in Andeok, **the largest camellia arboretum in the East** by acreage and species count: **6,000 camellia trees representing over 500 species sourced from 80 countries**, accumulated over **30+ years** of curation by founder Yang Jong-mun. The garden''s signature is its **year-round flowering calendar**, deliberately engineered so that visiting in any season produces a different color palette: **November–March = camellia peak** (red, pink, white, cream-beige varieties — the garden''s namesake season); **March–May = cherry blossoms + tulips + late camellias** layered together in dense color mass; **June–August = hydrangeas** (both outdoor stands and a climate-controlled greenhouse showing year-round display); **September–October = fall foliage + late-season bloomers**. Walking paths thread through themed sections — **European Garden, Korean Native Forest Section, Cherry Blossom Walk, Hydrangea Field** — connected by a winding 2.5-km loop that takes ~60–75 min to complete at a leisurely pace. Notable architectural moment: a **glass greenhouse + gallery + cafe** complex at the entrance, which serves as both indoor weather refuge (the only ~15% indoor portion of the visit) and a tea/coffee dwell space with garden views. **Drama filming credit**: variety show **''EXchange / Transit Love 3'' (환승연애)** featured Camellia Hill as the location of Ju-won and Yu-jeong''s memorable date scene — a draw for fans of the K-reality genre. **Open 365 days a year**; **no outdoor lighting** means the garden closes at sundown (winter ~17:00, summer ~19:00). Admission: **Adult ₩12,000 / Youth + Senior ₩10,000 / Child (4–11) ₩9,000 / FREE under 3**.","image":"https://images.unsplash.com/photo-1490750967868-88aa4486c946","highlights":["**172,000 m²** — largest camellia arboretum in the East","**6,000 trees / 500+ species from 80 countries** — accumulated 30+ years","**Year-round bloom calendar** — Nov–Mar camellias, Mar–May cherry + tulip, Jun–Aug hydrangea","**Themed sections**: European Garden, Korean Native Forest, Cherry Walk, Hydrangea Field","Glass **greenhouse + gallery + cafe** complex — indoor refuge (15% of visit)","**''EXchange / Transit Love 3''** filming location — Ju-won & Yu-jeong''s date scene","**Open 365 days**; closes at sundown (no outdoor lighting)","Admission **₩12,000 adult / ₩10,000 youth+senior / ₩9,000 child (4–11) / FREE under 3**","**~85% outdoor** garden walking — comfortable shoes recommended"],"timeUsed":["Parking + entrance + welcome — ~10 min","Camellia + featured-bloom section walk — ~25 min","European Garden + Hydrangea Field — ~20 min","Greenhouse + cafe break (optional) — ~15 min","Buffer / restroom — ~5 min"],"whyOnRoute":"**Camellia Hill is the day''s winter-bloom signature** — the **172,000 m² East-Asia-largest camellia arboretum (6,000 trees / 500+ species from 80 countries)** is at **peak bloom Nov–Mar**, exactly when most other Jeju gardens are dormant. The winter visit captures **deep-red and white camellia petals against snow on Hallasan in the distance** — a juxtaposition unique to Jeju''s mild winter climate (Hallasan snow + sub-tropical evergreen camellia bloom in the same eyeline). Position **fifth in the day** (14:30 post-lunch) puts the group at Camellia Hill in the **best afternoon light** for the red-on-white photographic pairing. Camellia Hill is also the catalog''s **''open 365 days a year''** Jeju garden — winter reliability is built-in. **~30 min from tangerine farm + lunch venue** keeps the day''s drive blocks short. K-drama ''EXchange / Transit Love 3'' (환승연애) filming (catalog-novel reference for winter visitors who follow Korean dating shows) is a soft anchor for younger demographic guests.","_poi_meta":{"poi_key":"camellia_hill","kb_version":"1.20","verified_date":"2026-04-29","sources":["Camellia Hill official site (camelliahill.co.kr)","VisitJeju — Camellia Hill official listing","Andeok-myeon cultural tourism office","Korea Tourism Organization — Top Korean botanical gardens registry","Kakao TV / Wavve programming archive — ''EXchange / Transit Love 3'' filming locations"]}},{"number":6,"time":"16:00","duration":"45 min","name":"Daepo Jusangjeolli Cliff","category":"Volcanic Coastline — Hexagonal Columnar-Jointed Lava","description":"**Daepo Jusangjeolli (대포 주상절리, ''Jisatgae'')** is a **1 km stretch of hexagonal columnar-jointed basalt cliff** on the Jungmun coast — designated **Natural Monument No. 443 on 2005-01-06**. The columns rise **30–40 m** from the sea, packed in tightly fitted **5- to 7-sided polygons** (mostly hexagons) — a geometry produced when **molten basaltic lava from a Hallasan flank eruption (~250,000–140,000 years ago) reached the ocean and contracted as it cooled**, fracturing perpendicular to the cooling surface. Globally, columnar jointing is best known from **Giant''s Causeway (UK)**, **Devils Postpile (US)**, and **Fingal''s Cave (Scotland)** — Jusangjeolli is **East Asia''s premier example** and the most accessible. The 800 m **boardwalk loop** delivers visitors to a railed cliff edge directly above the columns; **on high-tide days waves break against the columns and throw spray up to 20 m**, occasionally over the rail. Admission: **Adult ₩2,000 / Youth ₩1,000 / FREE under 7 and over 65**. The site is part of the **Jeju Global Geopark (UNESCO designated 2010-10)** — one of **13 official geosites** on the island, alongside Seongsan Ilchulbong, Manjanggul Lava Tube, and Suwolbong. The clifftop deck is **barrier-free** (wheelchair/stroller accessible). Three viewing platforms along the loop give different column angles: the **first platform** shows the columns in profile (best for the hexagonal-geometry shot), the **mid-platform** looks straight down for top-of-column patterns, and the **far platform** captures the 1 km coastal sweep with Hallasan as backdrop on clear days. **Photographic peak window: 14:00–16:00**, when westering sunlight lights the column faces frontally; sunset visits bring silhouette compositions but lose column-detail texture. Hours: **09:00–18:00 (last entry 17:30)**, year-round operation.","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee","highlights":["**Natural Monument No. 443** — designated **2005-01-06**, the most recent Jeju coastal NM","Columns rise **30–40 m**, packed in **5- to 7-sided polygons** (mostly hexagons) along **1 km** of coastline","Formation: **Hallasan flank lava cooled in the sea ~250,000–140,000 years ago**, contracting perpendicular to cooling face","**East Asia''s premier columnar-jointing site** — peer to Giant''s Causeway, Devils Postpile, Fingal''s Cave","**Spray up to 20 m on high-tide days** — wave-fountain photography window","**0.8 km boardwalk loop**, ~15 min walk — barrier-free deck, wheelchair/stroller accessible","Part of **Jeju Global Geopark (UNESCO 2010-10)** — 13 island-wide geosites","Admission **₩2,000 adult / ₩1,000 youth / FREE under 7 + over 65**","Hallasan summit visible to the north on clear days, **directly downstream** geologically"],"timeUsed":["Parking + ticket purchase + entrance — ~5 min","Walk to first viewing platform — ~5 min","Cliff-edge column viewing + photos — ~15 min","Continue boardwalk loop — ~10 min","Return to coach — ~10 min"],"whyOnRoute":"**Jusangjeolli Cliff (Natural Monument No. 443, designated 2005-01-06)** is the day''s geological anchor — **East Asian peer to Giant''s Causeway, Devils Postpile, and Fingal''s Cave**: Hallasan-flank lava reaching the sea ~250,000–140,000 years ago contracted perpendicular to the cooling face, producing the iconic hexagonal-pentagonal columnar joints. **Winter visit advantage**: the **basalt cliff is dramatically backlit by low-angle winter afternoon sun** (sunset window ~17:30 in Dec–Jan), and **winter ocean swells** (Nov–Feb peak) deliver some of the year''s most dramatic wave-crash scenes against the columnar cliff face — a markedly different atmosphere from the calmer summer surf. The **paved cliff-edge walkway** (~15-min full circuit, railings throughout) is **family-safe even in winter wind**; the operator advises layered jackets here as the cliff is wind-exposed. Pairing with Hallasan in the morning gives the day a **vertical geology arc** — alpine snow origin → coastal lava terminus, the same volcanic system from peak to sea. **Position sixth (16:00)** also positions the group for the day''s golden-hour light over the basalt + ocean.","_poi_meta":{"poi_key":"daepo_jusangjeolli_cliff","kb_version":"1.18","verified_date":"2026-04-29","sources":["Cultural Heritage Administration — Natural Monument No. 443 designation (2005-01-06)","Jeju Global Geopark official site (geopark.jeju.go.kr)","UNESCO Global Geoparks Network — Jeju (2010 designation)","VisitJeju — Daepo Jusangjeolli","Korea Geological Survey — Jeju basalt formation studies"]}},{"number":7,"time":"16:50","duration":"45 min","name":"Cheonjeyeon Waterfall","category":"Three-Tier Waterfall + Forest — ''Pond of the Emperor of Heaven''","description":"**Cheonjeyeon Falls (천제연, ''연 = pond + 천제 = Emperor of Heaven'')** is a **three-tier waterfall** in Jungmun''s volcanic gorge, designated **Natural Monument No. 378 (1993)** for its rare ecological combination. The name comes from a **Joseon-era Daoist legend that seven nymphs (선녀, *seonnyeo*) descended from heaven nightly to bathe in the upper pond** — a myth reinforced by the dramatic site''s microclimate of perpetual mist. The **1st tier (22 m fall, 21 m deep pond)** drops into a circular basalt cauldron and only flows after heavy rain — most days the upper pond sits glassy and reflective. The **2nd tier (30 m fall) flows year-round** — the dominant photographic subject. The 3rd tier completes the descent to the sea. The **120 m / 78 m-high Seonimgyo Bridge (선임교, ''Bridge of the Seven Nymphs'')** crosses the gorge midway through the loop — its cast-bronze relief panels along both sides depict **all seven nymphs in flight**, a literal architectural realization of the founding legend. Surrounding forest is a **rare-plant habitat** including **Korean toadlily (***Tricyrtis macropoda***)** and the endangered **Mankyua chejuense fern** (Jeju endemic, IUCN Critically Endangered). Loop length: **0.8 km, ~30 min walk** with several steep stair sections. Admission: **Adult ₩2,500 / Youth ₩1,350 / FREE under 7 + over 65**. Cheonjeyeon is also a member of the **''Yeongjusipgyeong (영주십경, 10 Scenic Wonders of Jeju)''** Joseon-era literati canon — alongside Hallasan summit, Seongsan Sunrise, and Jeongbang Falls — meaning today''s southwest loop covers **2 of the 10 (Hallasan + Cheonjeyeon)** in a single day. The biennial **Jeju Chilseonyeo (Seven Nymphs) Festival** held at the bridge in May (every odd year) reenacts the descent legend with traditional dance and musical performance — reservations required when the festival coincides with a tour date. Hours **09:00–18:00** year-round (last entry 17:30).","image":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e","highlights":["**Natural Monument No. 378 (designated 1993)** — three-tier waterfall + rare-plant habitat","Name **''Cheonjeyeon'' = ''Pond of the Emperor of Heaven''** — Joseon Daoist legend","**Seven Nymphs (선녀) legend** carved into the **120 m × 78 m Seonimgyo Bridge** relief panels","**1st tier (22 m / 21 m pond)** — only flows after heavy rain; **2nd tier (30 m) flows year-round**","Habitat for **Mankyua chejuense fern** — Jeju endemic, IUCN Critically Endangered","**0.8 km loop / ~30 min** — moderate stairs, footwear matters","Admission **₩2,500 adult / ₩1,350 youth / FREE under 7 + over 65**","**Jeju Chilseonyeo (Seven Nymphs) Festival** held biennially at the site — bridge ceremony","**Misty microclimate** — natural cooling, popular summer afternoon retreat"],"timeUsed":["Entrance + ticket — ~5 min","Descent to 1st tier viewing platform — ~10 min","1st tier + 2nd tier photography — ~20 min","Seonimgyo Bridge + nymph relief panels — ~15 min","Forest loop + ascent back to coach — ~25 min"],"whyOnRoute":"**Cheonjeyeon Falls** (''Pond of the Heavenly Emperor'', **Natural Monument No. 378**) is the day''s three-tier waterfall closer — **NOT to be confused with Cheonjiyeon (천지연, single-tier, NM 379)** in downtown Seogwipo. **Winter advantage**: the **Seonimgyo Bridge** (선임교 — ''Bridge of Seven Nymphs'' with seven-nymph carved relief, designed in 1984) is **illuminated after dark from ~17:30 in winter**, and the **late-afternoon visit (16:50–17:35)** captures the natural transition from daylight to the bridge''s evening illumination — a **catalog-unique ''winter twilight'' photography window** that summer tours miss entirely. **Three-tier cascade** structure: Tier 1 (22 m drop into emerald pool — water-only on rainy days; usually pool-only in winter dry season), Tier 2 (~30 m), Tier 3 (~5 m into final pool meeting the sea). **Yongyeon Pond** at Tier 1 is the protected habitat of the **Mutae eel** (marbled eel, NM 27 — same species as Cheonjiyeon''s). **~10 min drive from Jusangjeolli** continues the cliff-to-falls geological flow. **Final substantive stop** — the day closes with the most delicate scenery before evening drop-off.","_poi_meta":{"poi_key":"cheonjeyeon_falls","kb_version":"1.18","verified_date":"2026-04-29","sources":["Cultural Heritage Administration — Natural Monument No. 378 (1993 designation)","VisitJeju — Cheonjeyeon Pokpo official listing","Korea National Arboretum — Mankyua chejuense conservation records","Jeju Cultural Foundation — Seven Nymphs Festival history","Seogwipo City tourism — Cheonjeyeon admission and access"]}},{"number":8,"time":"17:30 → arrive Jeju City ≈ 18:30","duration":"60 min drive + drop-off","name":"Drop-off (Jeju City / Jungmun area)","category":"Return","description":"**Return drive to original pickup hotels** in Jeju City and Jungmun-area accommodations. The route from Cheonjeyeon Falls (Jungmun) splits — **Jungmun-area hotels are dropped off first** (~5 min from the falls), then the minicoach continues to Jeju City via Highway 1135 (~50 min). Drop-off is **typically at the original pickup hotel lobby**; guests who joined at off-hotel meeting points are returned to the same point unless otherwise requested. **Winter dispatch consideration**: if Route 1100 (the Hallasan ascent road used in the morning) has accumulated snow or freezing rain by evening, the return uses **alternative Route 1135 + 16** to avoid altitude exposure on the ride home. **Vehicle-side amenities**: hot tea/coffee remains available in the in-vehicle cooler; the guide can answer follow-up questions about Jeju (geology, citrus history, Korean dating-show filming, food tradition) during the return drive — a small-group day-tour''s natural conversational close. If guests have **next-day Jeju International Airport flights**, the guide can advise on **Bus 600** from Jungmun-area hotels (~75 min to airport) or downtown Jeju City taxi/Bus 100 connections (~30 min). Tip-jar protocol: guides do not solicit gratuity, but a customary tip range of **₩10,000–20,000/pax** is appreciated for full-day winter tours (cash or KakaoPay).","highlights":["**Jungmun hotels dropped first** (~5 min from Cheonjeyeon), then Jeju City (~50 min)","Return at original pickup hotel lobby or off-hotel meeting point","**Winter alternative routing** (Route 1135 + 16) when Route 1100 has overnight ice","Guide-led conversational close — Jeju Q&A during return drive","**Bus 600** advised for next-day airport connections from Jungmun","Customary tip range ₩10,000–20,000/pax (not solicited; cash or KakaoPay)"],"whyOnRoute":"**Drop-off timing 17:30 → 18:30 arrival** matches **post-sunset winter dinner window** in both Jeju City and Jungmun — guests have evening hours intact for hotel dinner or further exploration. Splitting Jungmun (drop first) vs Jeju City (drop second) optimizes total drive time across the 8–15 pax mix where guests typically split ~30/70 between Jungmun and Jeju City accommodations. Winter route flexibility (1100 vs 1135+16) protects against late-day road conditions that morning route doesn''t yet reflect.","_poi_meta":{"poi_key":"OPS_dropoff_winter_southwest","kb_version":"1.22","verified_date":"2026-04-29","sources":["AtoC Korea operations notes (Jeju winter return-route protocol)","Jeju Bus Information System (Bus 600 + Bus 100 airport connections)","Jeju Provincial Government (Highway 1135 + Route 16 winter alternates)"]}}],"routeFlowStops":[{"name":"Jeju City hotel","type":"origin","theme":"Departure"},{"name":"Hallasan viewpoint","type":"primary","theme":"Volcano"},{"name":"Tangerine farm","type":"primary","theme":"Stop"},{"name":"Lunch","type":"meal","theme":"Meal"},{"name":"Camellia Hill (winter peak)","type":"primary","theme":"Garden"},{"name":"Jusangjeolli Cliff","type":"secondary","theme":"Coast"},{"name":"Cheonjeyeon Falls","type":"secondary","theme":"Waterfall"},{"name":"Jeju City hotel","type":"return","theme":"Return"}],"routePhases":[{"phase":"Outbound","duration":"≈ 1 hour","description":"Jeju City → southwest interior to Hallasan viewpoint."},{"phase":"Hallasan + tangerine","duration":"≈ 2 hours","description":"Hallasan viewpoint then southwest tangerine orchard for hands-on picking."},{"phase":"Camellia peak","duration":"≈ 1.5 hours","description":"Camellia Hill — the winter headline stop."},{"phase":"South coast finale","duration":"≈ 1.5 hours","description":"Jusangjeolli columnar cliffs + Cheonjeyeon Falls."},{"phase":"Return","duration":"≈ 1 hour","description":"South coast → Jeju City."}],"routeShapeIntro":{"title":"How this day flows","subtitle":"A winter-only southwest loop. Jeju in December–February is mild on the coast (3–10°C) but snowy on Hallasan''s upper slopes — a contrast that doesn''t exist anywhere else in Korea. The tour pairs the snow viewpoint with two seasonal-peak experiences (red camellia in full bloom, gyul orchards at harvest) plus the standard south-coast UNESCO sites that work year-round. Most international visitors miss winter Jeju entirely; this is the route that makes the case."},"whyTourWorks":{"bestFor":["Travelers visiting Jeju in December-February who want all three winter-only stops (snow, camellia, tangerine) in one day","Photographers chasing camellia bloom, Hallasan snow, and tangerine harvest in a single frame range","Couples and adult families wanting a hands-on cultural moment (orchard picking)","First-time winter-Jeju visitors — the alternative is splitting these stops across two tour days","Travelers who prefer fixed-itinerary structure with cold-weather operational support"],"lessIdealFor":["Travelers visiting outside December-February — camellia and tangerine harvest are season-locked","Visitors who want deep Hallasan trekking (this stop is viewpoint-only)","Travelers needing wheelchair access at every stop (Cheonjeyeon has ≈ 80 stairs)","Same-day cruise passengers — winter operations have weather-dependent stop substitutions that complicate sailaway timing","Travelers without warm clothing — Hallasan can be 5-10°C colder than coastal Jeju with wind"],"routeLogicSections":[{"title":"Why this route is built this way","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Three winter-only stops in one day","detail":"Snow + camellia + tangerine harvest is a uniquely Jeju winter combination — none of these are available outside December–February. Doing all three independently means renting a car (in winter), booking a tangerine farm in advance, and timing the Hallasan viewpoint right. The tour collapses all that into one coordinated 9-hour day."},{"label":"Camellia Hill is at its annual peak","detail":"Camellia Hill is good year-round, but in winter (its namesake season) it''s at its absolute best — 6,000+ trees across 500 varieties from 80 countries in synchronized bloom. Other gardens are dormant. This single stop justifies the day for anyone who values winter flowers."},{"label":"Hands-on tangerine picking, not a photo stop","detail":"Most flower-and-citrus tours include a ''tangerine cafe'' visit where you buy a single fruit. This route uses a working orchard where you actually pick, taste-test, and take 1 kg home. The orchard fee (₩5,000) is paid on-site to the farmer."},{"label":"No hiking required, but you''ll see snow","detail":"Many visitors want winter scenery without the gear, fitness, or risk of an actual mountain hike. The Hallasan viewpoint stop along the 1100 Road delivers snow views from a heated vehicle and a brief walk — perfect for travelers who want the photograph without the climb."}]},{"title":"How the walking load actually feels","icon":"footprints","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Hallasan viewpoint is mostly drive-up","detail":"A roadside stop or a short flat walk depending on weather and road conditions. This is not a hike."},{"label":"Camellia Hill is large but flat","detail":"About 4-6 km of paved garden paths total; most travelers walk 1-2 km of selected routes. Senior-friendly with paved surfaces throughout."},{"label":"Cheonjeyeon stairs are the only demanding section","detail":"The upper viewing platform requires no stairs and can substitute if the second-tier descent is too much. About 80 stairs to the lower tiers and back."}]},{"title":"When weather and seasons shift","icon":"cloud-snow","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Hallasan 1100 Road closes in heavy snow","detail":"Typically 1-3 days per winter. The operator swaps to Sanbangsan Mountain or the O''sulloc Tea Museum, both nearby."},{"label":"Camellia Hill peaks in January","detail":"December starts the bloom; February still strong through mid-month. January is the absolute peak for synchronized flowering across the 250 varieties."},{"label":"Tangerine harvest tapers in February","detail":"December and January are the strongest picking months. By mid-February some orchards close the picking experience as fruit volume drops."}]}]},"practicalAccordionItems":[{"id":"inclusions","title":"What''s included","preview":"Heated vehicle, licensed English/Chinese-speaking guide-driver, fuel, tolls, parking.","content":["Heated vehicle, licensed English/Chinese-speaking guide-driver, fuel, tolls, parking.","Not included: attraction admissions (Camellia Hill ₩10,000, Cheonjeyeon Falls ₩2,500, Jusangjeolli ₩2,000), tangerine-picking fee ₩5,000 (paid on-site to the farmer), lunch, tips.","Total typical out-of-pocket per person: ₩25,000–₩35,000."]},{"id":"pickup","title":"Pickup & drop-off","preview":"Free hotel pickup within Jeju City.","content":["Free hotel pickup within Jeju City.","Outside Jeju City (Seogwipo, Aewol, Seongsan) pickup adds ₩70,000 paid to the driver.","Confirm pickup location at booking.","Jeju Airport pickup also free if arranged."]},{"id":"walking","title":"Walking & terrain","preview":"Light to moderate.","content":["Light to moderate.","The Hallasan viewpoint is a roadside stop or short flat walk.","Camellia Hill is large but flat with paved paths.","Cheonjeyeon Falls has stairs to the lower viewpoint.","Jusangjeolli has a boardwalk with railings.","Comfortable closed-toe shoes recommended."]},{"id":"what","title":"What to bring (winter Jeju)","preview":"Warm coat, gloves, scarf — Hallasan can be 5–10°C colder than coastal Jeju, with wind.","content":["Warm coat, gloves, scarf — Hallasan can be 5–10°C colder than coastal Jeju, with wind.","Closed-toe shoes (no sandals — orchard floor is muddy).","Camera.","Cash for tangerine-picking fee (₩5,000) and admissions.","Pre-purchased gloves available at major sites if you forget."]},{"id":"cancellation","title":"Cancellation","preview":"Free cancellation up to 24 hours before pickup.","content":["Free cancellation up to 24 hours before pickup.","Same-day cancellations and no-shows are non-refundable.","Heavy snow on Hallasan may close the 1100 Road — in that case the route adjusts to skip the snow viewpoint and add an alternate stop."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"See seasonal notes"},"tomorrow":{"temp":"—","label":"See seasonal notes"},"_seasonalSummary":"Jeju winter (Dec–Feb) is the mildest in Korea — coastal areas hover at 3–10°C — but Hallasan''s upper slopes are 5–10°C colder with snow possible. Wind is the dominant factor at the Hallasan viewpoint.","_seasonalTemperatures":[{"season":"Coastal Dec–Feb","range":"3–10°C","notes":"Mild for Korea; coat needed but rarely freezing."},{"season":"Hallasan upper slopes","range":"-5 to 5°C","notes":"Wind chill significant; snow likely Jan–Feb."},{"season":"Tangerine orchard","range":"5–12°C","notes":"Sheltered low-altitude valley; pick-your-own works fine in winter."}]},"seasonalVariations":[{"season":"December","description":"Camellia bloom begins, tangerine harvest peak. Less snow on Hallasan typically."},{"season":"January","description":"Camellia at absolute peak. Most likely month for snow on Hallasan. Tangerine still in season."},{"season":"February","description":"Camellia still strong through mid-month. Snow likely. Tangerine season ending."},{"season":"Outside Dec–Feb","description":"Tour does not run in summer — see East Hydrangea Festival tour or autumn Pink Muhly tour for seasonal alternates."}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local operator","description":"Authorized Korean tour operator with full insurance","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Route specialists","description":"Hand-tuned itinerary, not a generic loop","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Curated group size","description":"Right-sized for the route","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"12 hours before","title":"12-Hour Reminder","detail":"Weather update and any route adjustments"},{"timing":"Evening before","title":"Final Pickup Info","detail":"Exact pickup time and driver contact"},{"timing":"Morning of tour","title":"Day-of Route Notes","detail":"Morning briefing based on live conditions"},{"timing":"During tour","title":"Stop-by-Stop Tips","detail":"Real-time guidance at each location"},{"timing":"After tour","title":"Post-tour Support","detail":"Follow-up and recommendations"}],"staticQuestions":[{"id":"q1","question":"Will I actually see snow?","answer":"Snow on Hallasan is typical December through February but not guaranteed every visit. January is the most likely month. The viewpoint route still delivers strong winter mountain scenery even on snowless days. Camellia and tangerine stops are weather-independent."},{"id":"q2","question":"Are admissions and the picking fee included?","answer":"No. Budget about ₩25,000–₩35,000 per person for admissions plus ₩5,000 for the tangerine-picking fee paid on-site at the orchard."},{"id":"q3","question":"Can children pick tangerines?","answer":"Yes — tangerine picking is family-friendly and children especially enjoy it. Clippers and baskets are provided. Children pay the same orchard fee as adults; under-3s typically free."},{"id":"q4","question":"Is this tour available in summer?","answer":"No — the camellia and tangerine stops are winter-specific. For summer, see the East Hydrangea Festival tour. For autumn, see the Pink Muhly + Tangerine tour."},{"id":"q5","question":"What if Hallasan is closed for snow?","answer":"Heavy snow can close the 1100 Road for safety. In that case, the guide swaps in an alternate stop — typically Sanbangsan Mountain or the Osulloc Tea Museum, both nearby. Camellia Hill and the orchard remain on the itinerary."},{"id":"q6","question":"How is this different from the East Winter tour?","answer":"Our Eastern Winter tour covers Seongsan Ilchulbong (UNESCO Sunrise Peak), the Haenyeo women-diver show, and the lava-tube cave. This Southwest version covers Hallasan snow + Camellia Hill + south-coast UNESCO sites (Jusangjeolli, Cheonjeyeon). Choose East for UNESCO peak and culture; Southwest for camellia headline and winter mountain views."},{"id":"first-time","question":"Is this a good choice for first-time visitors to Jeju in winter?","answer":"Yes — it covers the most distinctive stops in the area in a single balanced day."},{"id":"walking","question":"Is the walking difficult?","answer":"Light to moderate. The Hallasan viewpoint is roadside or a short flat walk (depending on weather). Camellia Hill has 4-6 km of optional paved garden paths — most travelers walk 1-2 km. The tangerine orchard is flat ground. Cheonjeyeon has 80+ stairs. Closed-toe shoes essential — orchard floor is muddy in winter."},{"id":"family","question":"Is this tour suitable for families?","answer":"Yes — tangerine picking is a family highlight. Camellia Hill has paved paths suitable for most ages. The Hallasan viewpoint is a quick stop. Kids should be dressed for temperatures 5-10°C colder than coastal Jeju on the mountain."},{"id":"seniors","question":"Can older adults join comfortably?","answer":"Yes for active seniors who can handle cold weather and stairs at Cheonjeyeon. The Hallasan viewpoint is roadside (no climb). Camellia Hill paths are paved. Less ideal for travelers needing snow-grip mobility aids in icy conditions."},{"id":"children","question":"What''s the recommended minimum age?","answer":"Age 6+ recommended. Kids enjoy hands-on tangerine picking; clippers and baskets provided. Camellia Hill is large but kids can walk shorter loops. Cheonjeyeon stairs are skippable. Younger children join with carriers and warm gear."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"","currency":"USD","per":"person","priceSource":"getyourguide_t1119639","priceNote":"Small-group price not yet confirmed from listing snippet. Sister tour (Pink Muhly autumn version) is approximately $111 per person. Once confirmed, AtoC Korea sale price applies a flat 10% discount.","discountPercent":10}},"pickup_dropoff":{"type":"hotel_pickup","meeting_points":[{"name":"Hotel within Jeju City","time":"≈08:30 (free)"},{"name":"Hotel outside Jeju City","time":"Earlier; +₩70,000 surcharge"},{"name":"Jeju International Airport","time":"≈08:30"}],"dropoff_points":[{"name":"Hotel in Jeju City","approx_time":"≈17:30"},{"name":"Dongmun Traditional Market","approx_time":"≈17:30"},{"name":"Jeju Airport","approx_time":"≈17:30"}],"hotel_pickup_available":true,"notes":"Tour runs December through February only. Snow on Hallasan possible but not guaranteed. Outside-Jeju-City pickup adds ₩70,000."},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"jeju-winter-s