inter","flower_lovers"],"not_recommended_for":["summer_visitors_off_season","private_tour_seekers","beach_seekers"],"anchor_pois":["Hallasan viewpoint","Camellia Hill","Jeju tangerine orchard","Jusangjeolli Cliff","Cheonjeyeon Falls"],"competing_products":["jeju-west-south-full-day-authentic-tour","jeju-southern-top-unesco-spots-tour","jeju-hydrangea-festival-tour-southwest-route","jeju-eastern-unesco-spots-day-tour"],"anchor_poi_keys":["hallasan_1100_wetland","camellia_hill","tangerine_farm","jusangjeolli_cliff","cheonjeyeon_falls"],"enrichment_batch":"16b","enrichment_date":"2026-04-29","enrichment_kb_version":"1.22","enrichment_target_kb_version":"1.23","profile_version_pre":5,"profile_version_post":6,"schema_version":7,"stop_count_total":8,"substantive_stop_count":5,"auxiliary_stop_count":3,"highlight_count_per_substantive_stop":9,"source_count_per_substantive_stop_min":5,"cross_batch_reuse_map":{"camellia_hill":"from batch15a_tour1_data (1734c canonical, winter framing override)","daepo_jusangjeolli_cliff":"from batch14a_tour1_data (1831c canonical, winter framing override)","cheonjeyeon_falls":"from batch14a_tour2_data (1914c canonical, winter twilight framing override)"},"fresh_authoring_map":{"hallasan_eorimok_trail":"FRESH from KB v1.22 (38 facts → ~2200c stop body)","jeju_tangerine_picking_experience":"FRESH from KB v1.22 (45 facts → ~2400c stop body)"},"single_tour_no_sister":true,"catalog_completion_milestone":"Brings catalog to 30/30 pv=6 (100% completion)","season_lock":"December-February only; winter_only_seasonality_fit=1.0"},"itinerary_variants":[],"_publication":{"schema_version":"v4_canonical","last_modified":"2026-04-28","version_history":["v11","v12","v13","v14","v15"],"fix_passes":{"v12":"P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned","v13":"P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 canonical (no Tailwind in data)","v14":"P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing","v15":"P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.","v17_schema_unification":{"date":"2026-04-28","description":"Phase 1: Converted matching_profile scores from 1-5 int scale to 0-1 float scale to match the 3 Step 3 new tours. Mapping 1→0.20, 2→0.40, 3→0.60, 4→0.80, 5→1.00. Mechanical conversion preserves ordinal information; verified-fact recalibration happens in subsequent enhancement batches.","fields_converted":43,"fields_skipped":0,"fields_already_float":0},"v17_batch5_enhancement":{"date":"2026-04-29","description":"Batch 5 deep enhancement — descriptions raised to 700-1300+ chars; KB-backed metadata on all attraction stops; matching_profile recalibrated with verified-fact 0-1 float scores. Time-weighted indoor_ratio per Fix 1 methodology.","_score_audit":{"_methodology":"0-1 float scale. Indoor ratio computed time-weighted. This is a winter-focused outdoor tour with intentionally high outdoor exposure for snow/cold experience.","deltas_applied":{"unesco_fit":{"old":0.6,"new":0.55,"reasoning":"Verified: Hallasan is UNESCO World Natural Heritage (2007). 1/6 stops UNESCO. 0.55 calibrated."},"walking_level":{"old":0.6,"new":0.65,"reasoning":"Verified: Hallasan Eorimok requires 1-2 km mountain trail walking (with crampons winter); other stops moderate. 0.65 — the Hallasan component pushes walking level up."},"scenic_level":{"old":1,"new":0.95,"reasoning":"Verified: snow-covered Hallasan plateau + tangerine orchards + camellia hill + columnar cliff + three-tier waterfall = catalog-leading winter scenic diversity. 0.95."},"photo_level":{"old":1,"new":0.95,"reasoning":"Verified: snow + red camellia + orange tangerines + black basalt + waterfall = catalog-leading visual contrast palette. 0.95 — uniquely photogenic combination available only Dec-Feb."},"iconic_landmark_fit":{"old":0.8,"new":0.85,"reasoning":"Verified: Hallasan UNESCO + Camellia Hill regional icon + Jusangjeolli Natural Monument + Cheonjeyeon iconic 3-tier falls. 4 strong icons. 0.85."},"indoor_ratio":{"old":0.4,"new":0.1,"reasoning":"MAJOR CORRECTION — winter tour is intentionally outdoor-heavy: 67.5 indoor / 390 total = 0.17 with lunch; 19.5/330 = 0.06 without. Catalog 0.10 calibrated. The Hallasan + tangerine orchards + Jusangjeolli are all 0-10% indoor."},"weather_sensitivity":{"old":1,"new":0.95,"reasoning":"VERIFIED HIGHEST — winter snow tour completely weather-dependent: blizzard cancels Hallasan, ice closes orchards, rain reduces camellia photos. Highest weather sensitivity in catalog along with cherry blossom tours."},"rain_fit":{"old":0.4,"new":0.3,"reasoning":"DOWNGRADED — winter tour particularly rain-vulnerable: Hallasan trail in rain becomes dangerous, tangerine picking moves to greenhouse only, Jusangjeolli loses dramatic photo. 0.30 honest assessment."},"snow_fit":{"old":0.8,"new":0.95,"reasoning":"UPGRADED — this is THE catalog tour designed for snow. Snow on Hallasan is the FEATURE (not bug). Camellia red + snow white is signature. 0.95 — highest snow-fit in catalog."},"first_time_fit":{"old":0.8,"new":0.75,"reasoning":"Verified: excellent winter first-Jeju but season-locked to mid-Dec to mid-Jan for Hallabong window + camellia winter peak + best snow. 0.75 calibrated for narrow season."},"value_for_money_fit":{"old":0.6,"new":0.75,"reasoning":"Verified fees: Hallasan FREE + Tangerine ~₩7,000-15,000 + Camellia ₩9,000 + Jusangjeolli ₩2,000 + Cheonjeyeon ₩2,500 = ~₩22,500/adult. Hallasan free is a major value driver. 0.75."},"young_kids_fit":{"old":0.6,"new":0.65,"reasoning":"Verified: tangerine picking is highly kid-friendly + Camellia + Jusangjeolli. Hallasan trail + winter cold limit youngest kids. 0.65."},"senior_fit":{"old":0.4,"new":0.5,"reasoning":"UPGRADED — 1100 Wetland fallback option makes it senior-accessible; tangerine + Camellia + Jusangjeolli boardwalk all flat. Eorimok hike is the one challenge for seniors. 0.50."},"stroller_fit":{"old":0.4,"new":0.45,"reasoning":"Hallasan trail not stroller-friendly (snow + uneven terrain); other stops stroller-OK. 0.45 calibrated for the Hallasan limitation."},"mobility_friendly_fit":{"old":0.4,"new":0.45,"reasoning":"Same as stroller — Hallasan winter trail is the mobility limitation; 1100 Wetland boardwalk fallback helps. 0.45."},"active_fit":{"old":0.6,"new":0.85,"reasoning":"UPGRADED — winter mountain hike is the active component. Catalog-leading active winter content. 0.85."},"nature_fit":{"old":0.8,"new":0.95,"reasoning":"UPGRADED — UNESCO mountain + agricultural orchard + flower garden + columnar cliff + waterfall = catalog-leading winter nature density. 0.95."},"experiential_fit":{"old":0.8,"new":0.9,"reasoning":"Verified: tangerine picking is hands-on agricultural experience — eat-as-you-pick + take-home + 1,500-year tradition narrative. Strongest experiential anchor on the winter route. 0.90."},"geological_fit":{"old":0.6,"new":0.75,"reasoning":"Verified: Hallasan UNESCO volcanic + Jusangjeolli columnar joints. 2 strong geological landmarks. 0.75."}}},"stops_enhanced":8,"sources":["VisitKorea","Visit Jeju","Hallim Park CVB","AllTrails","Hunting for Bliss","Soul of Seoul","Roaming Sonaa","Trazy","KKday","NOL World"],"_extended_dimensions_documented_only":{"note":"These dimensions (snow_fit, active_fit, geological_fit, experiential_fit) were assessed during the v17 verified-fact audit but are NOT yet part of the standard 68-key matching_profile. They are preserved here as documentation for future schema extension.","values":{"snow_fit":0.95,"experiential_fit":0.9,"geological_fit":0.75,"active_fit":0.85}}}}}}'::jsonb
